class Solution:
    def gardenNoAdj(self, n, paths):
        adj = [[] for _ in range(n + 1)]
        for x, y in paths:
            adj[x].append(y)
            adj[y].append(x)
        color = [0] * (n + 1)
        for g in range(1, n + 1):
            taken = set()
            for nb in adj[g]:
                if color[nb]:
                    taken.add(color[nb])
            for c in (1, 2, 3, 4):
                if c not in taken:
                    color[g] = c
                    break
        return color[1:]

