            adj[x].append(y)
            adj[y].append(x)
        res = [0] * (n + 1)
        for g in range(1, n + 1):
            used = {res[nb] for nb in adj[g]}
            for c in (1, 2, 3, 4):
                if c not in used:
                    res[g] = c
                    break
        return res[1:]

