var gardenNoAdj = function(n, paths) {
    const adj = Array.from({length: n + 1}, () => []);
    for (const [x, y] of paths) {
        adj[x].push(y);
        adj[y].push(x);
    }
    const res = new Array(n + 1).fill(0);
    for (let g = 1; g <= n; g++) {
        const used = new Set();
        for (const nb of adj[g]) used.add(res[nb]);
        for (let c = 1; c <= 4; c++) {
            if (!used.has(c)) { res[g] = c; break; }
        }
    }
    return res.slice(1);
};
